INSERT INTO public.covers (title, musician, cover_artist, artist_role, year, label, genre, curator_note, spotify_id, hue, sat, lit, contributors, status) VALUES
('The Dark Side of the Moon', 'Pink Floyd', 'Storm Thorgerson', 'Art Direction', 1973, 'Harvest', ARRAY['Rock'], 'Thorgerson''s prism design is perhaps the most recognized album cover in history — minimal, bold, and endlessly imitated.', '4LH4d3cOWNNsVw41Gqt2kv', 220, 10, 12, '[]', 'approved'),
('Abbey Road', 'The Beatles', 'Iain Macmillan', 'Photography', 1969, 'Apple', ARRAY['Rock'], 'A single crosswalk photograph became one of the most parodied images in music. Macmillan had ten minutes and six shots.', '0ETFjACtuP2ADo6LFhL6HN', 200, 15, 60, '[]', 'approved'),
('Kind of Blue', 'Miles Davis', 'Jay Maisel', 'Photography', 1959, 'Columbia', ARRAY['Jazz'], 'Maisel''s close-up of Davis, eyes shut in concentration, perfectly mirrors the introspective cool of the music inside.', '1weenld61qoidwYuZ1GESA', 220, 40, 30, '[]', 'approved'),
('A Love Supreme', 'John Coltrane', 'Bob Thiele', 'Art Direction', 1965, 'Impulse!', ARRAY['Jazz'], 'The stark portrait with hand-lettered title evokes the spiritual intensity of Coltrane''s masterwork.', '7Eoz7hJvaX1eFkbpQxC5PA', 30, 60, 25, '[]', 'approved'),
('Selected Ambient Works 85–92', 'Aphex Twin', 'Paul Nicholson', 'Illustration', 1992, 'Apollo', ARRAY['Electronic'], 'The minimal geometric logo against deep blue became a totem for the ambient electronic movement.', '7aNclGRxTysfh6z0d8671k', 240, 50, 18, '[]', 'approved'),
('Homework', 'Daft Punk', 'Alex & Martin', 'Art Direction', 1997, 'Virgin', ARRAY['Electronic'], 'Clean modernist typography over textured metal — the cover channeled the anonymous machine aesthetic that defined the duo.', '5uRdvUR7xCnHmUW8n64n9y', 0, 0, 25, '[]', 'approved'),
('Illmatic', 'Nas', 'Danny Clinch', 'Photography', 1994, 'Columbia', ARRAY['Hip-hop'], 'The superimposed child portrait over the Queensbridge projects is a visceral map of origin — haunting and beautiful.', '3kEtdS2pH6hKcMU9Wioob1', 35, 50, 35, '[]', 'approved'),
('Madvillainy', 'Madvillain', 'Jeff Jank', 'Illustration', 2004, 'Stones Throw', ARRAY['Hip-hop'], 'Jank''s comic-book style perfectly captured the off-kilter, villainous persona of DOOM and Madlib''s collaboration.', '1EHSCvNFbcs0ADjoNB014v', 340, 50, 28, '[]', 'approved'),
('Blade Runner (Original Soundtrack)', 'Vangelis', 'John Alvin', 'Illustration', 1982, 'Full Moon', ARRAY['Soundtracks'], 'The neon-drenched cityscape painting mirrors the film''s dystopian beauty and became inseparable from the music.', '6NkuCdMz5tGmHbOXAWbtCW', 260, 55, 22, '[]', 'approved'),
('Head Hunters', 'Herbie Hancock', 'Victor Moscoso', 'Illustration', 1973, 'Columbia', ARRAY['Jazz'], 'Moscoso''s psychedelic illustration of Hancock as a mechanical shaman bridges jazz, funk, and the counterculture.', '5fmIolILp5NAtNYiRPjhzA', 120, 50, 30, '[]', 'approved'),
('Random Access Memories', 'Daft Punk', 'Warren Fu', 'Art Direction', 2013, 'Columbia', ARRAY['Electronic'], 'The chrome helmets shot with analog precision — Fu''s art direction married retro-futurism with pristine execution.', '4m2880jivSbbyEGAKfITCa', 40, 70, 35, '[]', 'approved'),
('Remain in Light', 'Talking Heads', 'Tibor Kalman', 'Art Direction', 1980, 'Sire', ARRAY['Rock'], 'Kalman''s collaged, digitally warped portraits anticipated the fractured identity themes of the internet age by decades.', '1JvXxLsm0PxlGH4LXzqMGq', 0, 75, 45, '[]', 'approved'),
('Interstellar (Original Soundtrack)', 'Hans Zimmer', 'Lee Nutter', 'Photography', 2014, 'WaterTower', ARRAY['Soundtracks'], 'The vast cosmic imagery against pitch black channels the film''s awe — Zimmer''s organs seem to resonate visually.', '7a78GiEowpaCa7ZJs44xUU', 30, 20, 10, '[]', 'approved'),
('To Pimp a Butterfly', 'Kendrick Lamar', 'Denis Rouvre', 'Photography', 2015, 'TDE', ARRAY['Hip-hop'], 'Rouvre''s group portrait on the White House lawn is confrontational, celebratory, and historically charged all at once.', '7ycBtnsMtyVbbwTfJwRjSP', 45, 30, 40, '[]', 'approved'),
('El Madrileño', 'C. Tangana', 'Santos Bacana', 'Photography', 2021, 'Sony', ARRAY['Hip-hop', 'Pop'], 'Bacana''s tabloid-style portrait — cigarette, gold chains, raw swagger — turned C. Tangana into a pop-culture painting of modern Madrid.', '52QyC9nSbgtHFXyQRHsXJ9', 25, 55, 45, '[{"name": "Santos Bacana", "role": "Photography"}, {"name": "Ivan Floro", "role": "Illustration"}]', 'approved'),
('La Cantera', 'Guitarricadelafuente', 'Koln Studio', 'Art Direction', 2022, 'Universal', ARRAY['Pop'], 'The painterly, sun-drenched aesthetic channels Mediterranean warmth and nostalgia — a visual love letter to southern Spain.', '3BDwyojdwMAmBEsXZlyQjW', 40, 65, 55, '[]', 'approved'),
('MOTOMAMI', 'Rosalía', 'Filip Custic', 'Photography', 2022, 'Columbia', ARRAY['Pop', 'Electronic'], 'Custic''s clinical, hyper-stylized portrait strips pop stardom to its raw, confrontational core — a selfie as manifesto.', '6jbtHi5R0jMXoliU2OS0lo', 0, 0, 90, '[]', 'approved'),
('OK Computer', 'Radiohead', 'Stanley Donwood', 'Illustration', 1997, 'Parlophone', ARRAY['Rock'], 'Donwood''s layered collage of highways and digital noise became the defining visual of late-90s technological anxiety.', '6dVIqQ8qmQ5GBnJ9shOYGE', 200, 10, 70, '[]', 'approved'),
